#include <unordered_map>

class Solution {
public:
    Solution(vector<int>& w) {
        // Initialize the map with weights
        map<int, int> weightMap;
        for (int weight: w) {
            weightMap[weight]++;
        }
    }

    int pickIndex() {
        // Calculate the total weight
        int totalWeight = 0;
        for (auto weight: weightMap) {
            totalWeight += weight.second;
        }

        // Generate a random number between 0 and totalWeight
        int randomIndex = rand() % totalWeight + 1;

        // Return the corresponding index from the map
        return weightMap[randomIndex];
    }
};
```

